SELECT emotion_name, intensity_scale
FROM emotions
WHERE intensity_scale > 5;

SELECT AVG(intensity) AS average_intensity
FROM user_emotion_history
WHERE user_id = 0 AND phase_id = 0;

SELECT count
FROM emotion_data_collection
WHERE emotion_id = 1;

SELECT feedback_text
FROM feedback
WHERE feedback_id = 1;

SELECT MAX(intensity) AS max_intensity
FROM emotion_data_collection
WHERE phase_id = (SELECT phase_id FROM communication_phases WHERE phase_name = 'Before');

SELECT MAX(recorded_date) AS latest_emotion_check_in
FROM user_emotion_history
WHERE user_id = 0;

SELECT AVG(intensity) AS average_intensity
FROM user_emotion_history
WHERE user_id = 1;

SELECT emotion_name, intensity_scale
FROM emotions
ORDER BY intensity_scale DESC;

SELECT emotion_name, AVG(intensity_scale) AS average_intensity
FROM emotions
GROUP BY emotion_name;
